queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:job_id ?cg . ?child a :Educational_Jobs ; p:job_id ?cg . ?l p:school_id ?pg . ?parent a :Schools ; p:id ?pg . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Schools } }
  FILTER(?nf = ?total)
}

